// ============================================================================
// v11.2: 타입 상태 패턴 (Type State Pattern - Compile Time Magic)
// ============================================================================
// 목표: 상태를 타입으로 박제하여 컴파일 타임 안전성 보장

use std::time::Instant;

fn main() {
    println!("═══════════════════════════════════════════════════════════");
    println!("v11.2: 타입 상태 패턴");
    println!("불가능한 상태를 표현 불가능하게 만들기");
    println!("═══════════════════════════════════════════════════════════\n");

    section_1_state_as_type();
    section_2_consuming_methods();
    section_3_zero_sized_types();
    section_4_missile_system();
    section_5_builder_pattern_comparison();
    section_6_compile_time_safety();
    section_7_memory_layout();
    section_8_runtime_vs_compile_time();
    section_9_complex_state_transitions();
    section_10_api_autocomplete();
    section_11_performance_measurement();
    section_12_designer_perspective();
}

// ============================================================================
// 섹션 1: 상태를 타입으로 표현
// ============================================================================
fn section_1_state_as_type() {
    println!("\n📌 섹션 1: 상태를 타입으로 표현");
    println!("────────────────────────────────────────");

    // 상태를 나타내는 빈 구조체 (타입 마커)
    struct Off;
    struct On;

    // 제네릭으로 상태를 가짐
    struct Light<State> {
        brightness: u8,
        _state: std::marker::PhantomData<State>,
    }

    // Off 상태에서만 가능한 메서드
    impl Light<Off> {
        fn new() -> Self {
            println!("  불을 껐습니다");
            Light {
                brightness: 0,
                _state: std::marker::PhantomData,
            }
        }

        fn turn_on(self) -> Light<On> {
            println!("  불을 켰습니다");
            Light {
                brightness: 100,
                _state: std::marker::PhantomData,
            }
        }
    }

    // On 상태에서만 가능한 메서드
    impl Light<On> {
        fn turn_off(self) -> Light<Off> {
            println!("  불을 껐습니다");
            Light {
                brightness: 0,
                _state: std::marker::PhantomData,
            }
        }

        fn brightness(&self) -> u8 {
            self.brightness
        }
    }

    let light = Light::<Off>::new();
    let light = light.turn_on();
    println!("  밝기: {}%", light.brightness());
    let _light = light.turn_off();

    println!("\n  🔍 상태를 타입으로 표현:");
    println!("    ✅ Light<Off>와 Light<On>은 다른 타입");
    println!("    ✅ 각 상태에서 가능한 메서드만 정의");
    println!("    ❌ 불가능한 메서드 호출 = 컴파일 에러");
}

// ============================================================================
// 섹션 2: Consuming Methods와 소유권 이동
// ============================================================================
fn section_2_consuming_methods() {
    println!("\n📌 섹션 2: Consuming Methods와 소유권 이동");
    println!("────────────────────────────────────────");

    struct Created;
    struct Running;
    struct Finished;

    struct Process<S> {
        id: u32,
        _state: std::marker::PhantomData<S>,
    }

    impl Process<Created> {
        fn new(id: u32) -> Self {
            println!("  프로세스 {} 생성", id);
            Process {
                id,
                _state: std::marker::PhantomData,
            }
        }

        // self를 소유권으로 가져가 파괴하고 새 타입 반환
        fn start(self) -> Process<Running> {
            println!("  프로세스 {} 시작", self.id);
            Process {
                id: self.id,
                _state: std::marker::PhantomData,
            }
        }
    }

    impl Process<Running> {
        fn stop(self) -> Process<Finished> {
            println!("  프로세스 {} 종료", self.id);
            Process {
                id: self.id,
                _state: std::marker::PhantomData,
            }
        }
    }

    impl Process<Finished> {
        fn clean_up(self) {
            println!("  프로세스 {} 정리 완료", self.id);
        }
    }

    let p = Process::new(42);
    // println!("{}", p.id); // ❌ 에러: p가 start에 의해 소유권 이동됨

    let p = p.start();
    let p = p.stop();
    p.clean_up();

    println!("\n  💡 Consuming Methods:");
    println!("    ✅ self를 소비해서 새로운 타입 반환");
    println!("    ✅ 이전 상태의 변수는 더 이상 사용 불가");
    println!("    ✅ 순차적 강제");
}

// ============================================================================
// 섹션 3: ZST (Zero-Sized Types)
// ============================================================================
fn section_3_zero_sized_types() {
    println!("\n📌 섹션 3: ZST (Zero-Sized Types)");
    println!("────────────────────────────────────────");

    struct StateA;
    struct StateB;
    struct StateC;

    println!("  타입 크기 분석:");
    println!("    StateA: {} bytes", std::mem::size_of::<StateA>());
    println!("    StateB: {} bytes", std::mem::size_of::<StateB>());
    println!("    StateC: {} bytes", std::mem::size_of::<StateC>());

    struct Container<S> {
        data: u32,
        state: std::marker::PhantomData<S>,
    }

    println!("\n  Container 크기:");
    println!("    Container<StateA>: {} bytes", std::mem::size_of::<Container<StateA>>());
    println!("    Container<StateB>: {} bytes", std::mem::size_of::<Container<StateB>>());
    println!("    Container<StateC>: {} bytes", std::mem::size_of::<Container<StateC>>());

    println!("\n  🔍 ZST의 의미:");
    println!("    ✅ 상태 타입은 메모리를 차지하지 않음");
    println!("    ✅ 컴파일러만 체크용으로 사용");
    println!("    ✅ 런타임 오버헤드 0 (Zero-Cost Abstraction)");
    println!("    ✅ PhantomData: 타입 정보만 저장, 크기 0");
}

// ============================================================================
// 섹션 4: 미사일 시스템 예제
// ============================================================================
fn section_4_missile_system() {
    println!("\n📌 섹션 4: 미사일 시스템 예제");
    println!("────────────────────────────────────────");

    struct Idle;
    struct Targeted {
        coordinates: String,
    }
    struct Armed;

    struct MissileSystem<S> {
        name: String,
        _state: std::marker::PhantomData<S>,
    }

    impl MissileSystem<Idle> {
        fn new() -> Self {
            println!("  미사일 시스템 초기화: Idle 상태");
            MissileSystem {
                name: "ICBM-001".to_string(),
                _state: std::marker::PhantomData,
            }
        }

        fn set_target(self, coord: &str) -> MissileSystem<Targeted> {
            println!("  좌표 {} 입력", coord);
            MissileSystem {
                name: self.name,
                _state: std::marker::PhantomData,
            }
        }
    }

    impl MissileSystem<Targeted> {
        fn arm(self) -> MissileSystem<Armed> {
            println!("  안전장치 해제, Armed 상태로 진입");
            MissileSystem {
                name: self.name,
                _state: std::marker::PhantomData,
            }
        }
    }

    impl MissileSystem<Armed> {
        fn fire(self) {
            println!("  🚀 발사! 기록이 증명한다 gogs");
        }
    }

    // 정상 흐름
    let system = MissileSystem::new();
    let system = system.set_target("37.5°N, 127.0°E");
    let system = system.arm();
    system.fire();

    println!("\n  🔍 컴파일 에러 케이스 (주석):");
    println!("    system.fire(); // ❌ Idle 상태에는 fire 메서드 없음");
    println!("    system.arm();  // ❌ Idle에서 바로 arm 불가");
}

// ============================================================================
// 섹션 5: Builder 패턴과 비교
// ============================================================================
fn section_5_builder_pattern_comparison() {
    println!("\n📌 섹션 5: Builder 패턴과의 비교");
    println!("────────────────────────────────────────");

    // 런타임 검사 (Builder 패턴)
    struct ServerRuntime {
        host: Option<String>,
        port: Option<u16>,
        ready: bool,
    }

    impl ServerRuntime {
        fn new() -> Self {
            ServerRuntime {
                host: None,
                port: None,
                ready: false,
            }
        }

        fn set_host(mut self, host: String) -> Self {
            self.host = Some(host);
            self
        }

        fn set_port(mut self, port: u16) -> Self {
            self.port = Some(port);
            self
        }

        fn build(self) -> Result<String, String> {
            if self.host.is_none() || self.port.is_none() {
                Err("호스트와 포트를 설정하세요".to_string())
            } else {
                Ok(format!("{}:{}", self.host.unwrap(), self.port.unwrap()))
            }
        }
    }

    // 타입 상태 (Type State)
    struct SetHost;
    struct SetPort;
    struct Ready;

    struct ServerTypeState<S> {
        _state: std::marker::PhantomData<S>,
    }

    impl ServerTypeState<SetHost> {
        fn new() -> Self {
            ServerTypeState {
                _state: std::marker::PhantomData,
            }
        }

        fn set_host(self) -> ServerTypeState<SetPort> {
            println!("  호스트 설정");
            ServerTypeState {
                _state: std::marker::PhantomData,
            }
        }
    }

    impl ServerTypeState<SetPort> {
        fn set_port(self) -> ServerTypeState<Ready> {
            println!("  포트 설정");
            ServerTypeState {
                _state: std::marker::PhantomData,
            }
        }
    }

    impl ServerTypeState<Ready> {
        fn build(self) -> String {
            "준비 완료".to_string()  // 항상 성공
        }
    }

    println!("  런타임 검사 (Builder):");
    let server = ServerRuntime::new()
        .set_host("localhost".to_string())
        .set_port(8080);
    match server.build() {
        Ok(addr) => println!("    ✅ {}", addr),
        Err(e) => println!("    ❌ {}", e),
    }

    println!("\n  컴파일 타임 검사 (Type State):");
    let server = ServerTypeState::new()
        .set_host()
        .set_port()
        .build();
    println!("    ✅ {}", server);

    println!("\n  비교:");
    println!("    Builder: 런타임 에러 가능 ⚠️");
    println!("    Type State: 컴파일 에러로 불가능 ✅");
}

// ============================================================================
// 섹션 6: 컴파일 타임 안전성
// ============================================================================
fn section_6_compile_time_safety() {
    println!("\n📌 섹션 6: 컴파일 타임 안전성");
    println!("────────────────────────────────────────");

    struct Locked;
    struct Unlocked;

    struct Door<S> {
        _state: std::marker::PhantomData<S>,
    }

    impl Door<Locked> {
        fn new() -> Self {
            println!("  문이 잠겨 있습니다");
            Door {
                _state: std::marker::PhantomData,
            }
        }

        fn unlock(self) -> Door<Unlocked> {
            println!("  문이 열렸습니다");
            Door {
                _state: std::marker::PhantomData,
            }
        }
    }

    impl Door<Unlocked> {
        fn open(&self) {
            println!("  문을 통과할 수 있습니다");
        }

        fn lock(self) -> Door<Locked> {
            println!("  문이 다시 잠겼습니다");
            Door {
                _state: std::marker::PhantomData,
            }
        }
    }

    let door = Door::<Locked>::new();
    // door.open(); // ❌ 컴파일 에러: Locked 상태에는 open 메서드가 없음

    let door = door.unlock();
    door.open();  // ✅ Unlocked 상태에만 가능
    let _door = door.lock();

    println!("\n  🔍 컴파일 타임 안전성:");
    println!("    ✅ 잘못된 상태 전이 = 컴파일 에러");
    println!("    ✅ 가능한 메서드만 IDE 자동 완성에 표시");
    println!("    ✅ 런타임 성능 = 100% (모든 체크 컴파일 타임)");
}

// ============================================================================
// 섹션 7: 메모리 레이아웃
// ============================================================================
fn section_7_memory_layout() {
    println!("\n📌 섹션 7: 메모리 레이아웃");
    println!("────────────────────────────────────────");

    struct StateX;
    struct StateY;
    struct StateZ;

    struct Machine {
        id: u32,
        name: String,
        counter: u64,
    }

    struct StateMachine<S> {
        id: u32,
        name: String,
        counter: u64,
        _phantom: std::marker::PhantomData<S>,
    }

    println!("  일반 구조체 크기:");
    println!("    Machine: {} bytes", std::mem::size_of::<Machine>());

    println!("\n  타입 상태 구조체 크기:");
    println!("    StateMachine<StateX>: {} bytes", std::mem::size_of::<StateMachine<StateX>>());
    println!("    StateMachine<StateY>: {} bytes", std::mem::size_of::<StateMachine<StateY>>());
    println!("    StateMachine<StateZ>: {} bytes", std::mem::size_of::<StateMachine<StateZ>>());

    println!("\n  💡 메모리 특성:");
    println!("    ✅ 모든 상태가 같은 메모리 레이아웃");
    println!("    ✅ PhantomData는 0 크기");
    println!("    ✅ 컴파일러가 최적화 (인라인, 제거 등)");
    println!("    ✅ 런타임 오버헤드: 정확히 0");
}

// ============================================================================
// 섹션 8: 런타임 vs 컴파일타임
// ============================================================================
fn section_8_runtime_vs_compile_time() {
    println!("\n📌 섹션 8: 런타임 vs 컴파일타임");
    println!("────────────────────────────────────────");

    enum State {
        Off,
        On,
        Standby,
    }

    struct LampRuntime {
        state: State,
    }

    impl LampRuntime {
        fn new() -> Self {
            LampRuntime { state: State::Off }
        }

        fn turn_on(&mut self) {
            self.state = State::On;
        }

        fn get_brightness(&self) -> u8 {
            match self.state {
                State::Off => 0,
                State::On => 100,
                State::Standby => 10,
            }
        }
    }

    // 런타임 검사
    let start = Instant::now();
    let mut lamp = LampRuntime::new();
    for _ in 0..1_000_000 {
        lamp.turn_on();
        let _ = lamp.get_brightness();
    }
    let runtime_elapsed = start.elapsed();

    // 타입 상태
    struct Off;
    struct On;

    struct LampTypeState<S> {
        _state: std::marker::PhantomData<S>,
    }

    impl LampTypeState<Off> {
        fn turn_on(self) -> LampTypeState<On> {
            LampTypeState {
                _state: std::marker::PhantomData,
            }
        }
    }

    impl LampTypeState<On> {
        fn get_brightness(&self) -> u8 {
            100
        }
    }

    let start = Instant::now();
    for _ in 0..1_000_000 {
        let lamp = LampTypeState::<Off>::new();
        let lamp = lamp.turn_on();
        let _ = lamp.get_brightness();
    }
    let typesstate_elapsed = start.elapsed();

    println!("  성능 측정 (1M 반복):");
    println!("    런타임 검사: {:.3}ms", runtime_elapsed.as_secs_f64() * 1000.0);
    println!("    타입 상태:   {:.3}ms", typesstate_elapsed.as_secs_f64() * 1000.0);

    println!("\n  💡 결과:");
    println!("    타입 상태가 약간 더 빠름 (모든 체크 컴파일 타임)");

    fn new_off() -> LampTypeState<Off> {
        LampTypeState {
            _state: std::marker::PhantomData,
        }
    }
}

// ============================================================================
// 섹션 9: 복잡한 상태 전이
// ============================================================================
fn section_9_complex_state_transitions() {
    println!("\n📌 섹션 9: 복잡한 상태 전이");
    println!("────────────────────────────────────────");

    struct Init;
    struct Connecting;
    struct Connected;
    struct Authenticated;
    struct Ready;

    struct Connection<S> {
        url: String,
        _state: std::marker::PhantomData<S>,
    }

    impl Connection<Init> {
        fn new(url: &str) -> Self {
            println!("  1. 초기화");
            Connection {
                url: url.to_string(),
                _state: std::marker::PhantomData,
            }
        }

        fn connect(self) -> Connection<Connecting> {
            println!("  2. 연결 시도...");
            Connection {
                url: self.url,
                _state: std::marker::PhantomData,
            }
        }
    }

    impl Connection<Connecting> {
        fn on_connected(self) -> Connection<Connected> {
            println!("  3. 연결 성공!");
            Connection {
                url: self.url,
                _state: std::marker::PhantomData,
            }
        }
    }

    impl Connection<Connected> {
        fn authenticate(self, user: &str, pass: &str) -> Connection<Authenticated> {
            println!("  4. {}로 인증 중...", user);
            Connection {
                url: self.url,
                _state: std::marker::PhantomData,
            }
        }
    }

    impl Connection<Authenticated> {
        fn set_ready(self) -> Connection<Ready> {
            println!("  5. 준비 완료!");
            Connection {
                url: self.url,
                _state: std::marker::PhantomData,
            }
        }
    }

    impl Connection<Ready> {
        fn send(&self, msg: &str) -> String {
            format!("서버로 전송: {}", msg)
        }
    }

    let conn = Connection::<Init>::new("wss://api.example.com");
    let conn = conn.connect();
    let conn = conn.on_connected();
    let conn = conn.authenticate("user", "pass");
    let conn = conn.set_ready();
    println!("  결과: {}", conn.send("안녕하세요"));

    println!("\n  💡 복잡한 상태 전이:");
    println!("    ✅ 각 단계를 강제할 수 있음");
    println!("    ✅ 단계 건너뛰기 불가능");
    println!("    ✅ 코드가 자명함 (주석 필요 없음)");
}

// ============================================================================
// 섹션 10: API 자동 완성
// ============================================================================
fn section_10_api_autocomplete() {
    println!("\n📌 섹션 10: API 자동 완성의 강력함");
    println!("────────────────────────────────────────");

    struct Empty;
    struct HasName;
    struct HasEmail;
    struct Complete;

    struct FormBuilder<S> {
        _state: std::marker::PhantomData<S>,
    }

    impl FormBuilder<Empty> {
        fn new() -> Self {
            FormBuilder {
                _state: std::marker::PhantomData,
            }
        }

        fn name(self) -> FormBuilder<HasName> {
            FormBuilder {
                _state: std::marker::PhantomData,
            }
        }
    }

    impl FormBuilder<HasName> {
        fn email(self) -> FormBuilder<HasEmail> {
            FormBuilder {
                _state: std::marker::PhantomData,
            }
        }
    }

    impl FormBuilder<HasEmail> {
        fn build(self) -> String {
            "폼 완성!".to_string()
        }
    }

    println!("  IDE 자동 완성의 과정:");
    let builder = FormBuilder::new();
    println!("    builder. → [name, ...]");
    let builder = builder.name();
    println!("    builder. → [email, ...]");
    let builder = builder.email();
    println!("    builder. → [build, ...]");
    let result = builder.build();
    println!("  결과: {}", result);

    println!("\n  💡 IDE의 이점:");
    println!("    ✅ 현재 상태에서 가능한 메서드만 표시");
    println!("    ✅ 문서가 코드 자체");
    println!("    ✅ 실수할 여지가 없음");
}

// ============================================================================
// 섹션 11: 성능 측정
// ============================================================================
fn section_11_performance_measurement() {
    println!("\n📌 섹션 11: 성능 측정");
    println!("────────────────────────────────────────");

    struct State1;
    struct State2;
    struct State3;

    struct Item<S> {
        value: i32,
        _phantom: std::marker::PhantomData<S>,
    }

    impl Item<State1> {
        fn next(self) -> Item<State2> {
            Item {
                value: self.value,
                _phantom: std::marker::PhantomData,
            }
        }
    }

    impl Item<State2> {
        fn next(self) -> Item<State3> {
            Item {
                value: self.value,
                _phantom: std::marker::PhantomData,
            }
        }
    }

    impl Item<State3> {
        fn result(&self) -> i32 {
            self.value * 2
        }
    }

    let start = Instant::now();
    for i in 0..10_000_000 {
        let item = Item::<State1> {
            value: i,
            _phantom: std::marker::PhantomData,
        };
        let item = item.next();
        let item = item.next();
        let _ = item.result();
    }
    let elapsed = start.elapsed();

    println!("  10M 상태 전이:");
    println!("    시간: {:.2}ms", elapsed.as_secs_f64() * 1000.0);
